import{_ as d,o as a,c as l,a2 as e}from"./chunks/framework.DRBHoC6Q.js";const b=JSON.parse('{"title":"CEO现金流驾驶舱 V1.0 字段、算法与数据来源清单","description":"","frontmatter":{},"headers":[],"relativePath":"CEO现金流驾驶舱V1.0_字段算法与数据来源清单.md","filePath":"CEO现金流驾驶舱V1.0_字段算法与数据来源清单.md","lastUpdated":1783323851000}'),i={name:"CEO现金流驾驶舱V1.0_字段算法与数据来源清单.md"};function r(o,t,n,h,s,c){return a(),l("div",null,[...t[0]||(t[0]=[e(`<h1 id="ceo现金流驾驶舱-v1-0-字段、算法与数据来源清单" tabindex="-1">CEO现金流驾驶舱 V1.0 字段、算法与数据来源清单 <a class="header-anchor" href="#ceo现金流驾驶舱-v1-0-字段、算法与数据来源清单" aria-label="Permalink to &quot;CEO现金流驾驶舱 V1.0 字段、算法与数据来源清单&quot;">​</a></h1><p>文档版本：V1.0<br> 适用项目：CEO现金流经营决策系统 V1.0<br> 核心用途：明确每个指标的业务定义、展示命名、计算规则、数据来源、维护责任人与复核责任人。<br> 确认原则：所有核心字段、算法、阈值必须由 CEO 和 CFO 共同确认。</p><h2 id="一、文档目标" tabindex="-1">一、文档目标 <a class="header-anchor" href="#一、文档目标" aria-label="Permalink to &quot;一、文档目标&quot;">​</a></h2><p>本清单是 CEO现金流驾驶舱 V1.0 的核心规则文档。</p><p>它优先级高于前端工程化任务书，因为前端页面、后端接口、数据库模型和 AI 回答依据，都必须基于本清单确定。</p><p>本清单要解决四个问题：</p><ol><li>页面上每个数字叫什么；</li><li>这个数字的财务定义是什么；</li><li>这个数字怎么计算；</li><li>这个数字从哪里来、谁维护、谁复核。</li></ol><h2 id="二、确认边界" tabindex="-1">二、确认边界 <a class="header-anchor" href="#二、确认边界" aria-label="Permalink to &quot;二、确认边界&quot;">​</a></h2><p>本文件分为业务确认项和技术实现项，二者不能混在一起决策。</p><h3 id="_2-1-ceo-cfo-必须确认" tabindex="-1">2.1 CEO + CFO 必须确认 <a class="header-anchor" href="#_2-1-ceo-cfo-必须确认" aria-label="Permalink to &quot;2.1 CEO + CFO 必须确认&quot;">​</a></h3><ul><li>CEO 展示名称；</li><li>CFO 财务定义；</li><li>业务含义；</li><li>计算公式；</li><li>阈值规则；</li><li>数据来源；</li><li>数据维护人；</li><li>数据复核人；</li><li>复核状态；</li><li>是否可用于正式经营判断。</li></ul><h3 id="_2-2-技术团队确认" tabindex="-1">2.2 技术团队确认 <a class="header-anchor" href="#_2-2-技术团队确认" aria-label="Permalink to &quot;2.2 技术团队确认&quot;">​</a></h3><ul><li>英文字段名；</li><li>数据库字段类型；</li><li>接口字段结构；</li><li>枚举编码；</li><li>前后端命名规范；</li><li>是否拆表、是否冗余、是否需要索引。</li></ul><h3 id="_2-3-命名原则" tabindex="-1">2.3 命名原则 <a class="header-anchor" href="#_2-3-命名原则" aria-label="Permalink to &quot;2.3 命名原则&quot;">​</a></h3><p>文档中的英文技术字段名均为建议字段名，只用于帮助工程团队理解，不作为 CEO/CFO 的业务确认项。</p><p>最终技术字段名应在《接口与数据模型评审清单》中由前端、后端和全栈工程师确认。</p><h2 id="三、字段确认原则" tabindex="-1">三、字段确认原则 <a class="header-anchor" href="#三、字段确认原则" aria-label="Permalink to &quot;三、字段确认原则&quot;">​</a></h2><ol><li>CEO 看到的名称必须清晰、直观、便于经营判断；</li><li>CFO 确认的财务定义必须准确、可追溯、可复核；</li><li>所有指标必须有数据来源，不能只有页面展示；</li><li>所有计算字段必须有公式和参数；</li><li>未经 CFO 复核的数据，不能作为正式经营结论；</li><li>AI 助手回答经营问题时，必须引用本清单中的字段、算法和数据来源。</li></ol><h2 id="四、业务指标确认清单" tabindex="-1">四、业务指标确认清单 <a class="header-anchor" href="#四、业务指标确认清单" aria-label="Permalink to &quot;四、业务指标确认清单&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模块</th><th>CEO展示名称</th><th>CFO财务定义</th><th>业务类型</th><th>计算规则</th><th>数据来源</th><th>维护人</th><th>复核人</th><th>复核状态</th></tr></thead><tbody><tr><td>驾驶舱</td><td>本月可用现金</td><td>当前可用于经营支出的现金余额</td><td>金额</td><td>银行账户可用余额 + 可确认短期到账 - 已锁定支出</td><td>银行流水 / 财务表</td><td>财务</td><td>CFO</td><td>待确认</td></tr><tr><td>驾驶舱</td><td>本月预计回款</td><td>本月预计可到账的应收款总额</td><td>金额</td><td>本月应收款中预计到账金额求和</td><td>应收表 / 合同台账 / 业务表</td><td>财务 / 商务</td><td>CFO</td><td>待确认</td></tr><tr><td>驾驶舱</td><td>本月实际回款</td><td>本月已实际到账的客户回款</td><td>金额</td><td>本月银行流水中已确认为收入的回款求和</td><td>银行流水 / 财务复核</td><td>财务</td><td>CFO</td><td>待确认</td></tr><tr><td>驾驶舱</td><td>本月计划支出</td><td>本月已计划或待审批的支出总额</td><td>金额</td><td>已审批支出 + 待审批预计支出 + 固定经营支出</td><td>支出审批 / 预算表 / 财务表</td><td>财务 / 行政</td><td>CFO</td><td>待确认</td></tr><tr><td>驾驶舱</td><td>本月现金流缺口</td><td>本月现金是否不足的缺口金额</td><td>金额</td><td>本月计划支出 - 本月可用现金 - 本月预计回款</td><td>计算字段</td><td>系统</td><td>CFO</td><td>待确认</td></tr><tr><td>驾驶舱</td><td>管理费用可用额度</td><td>本月或本周期管理费用剩余额度</td><td>金额</td><td>管理费用预算 - 已发生管理费用 - 已审批待发生管理费用</td><td>预算表 / 支出审批 / 财务表</td><td>财务</td><td>CFO</td><td>待确认</td></tr><tr><td>回款风险</td><td>应收金额</td><td>客户应支付但尚未完全到账的金额</td><td>金额</td><td>合同应收金额 - 已到账金额</td><td>合同台账 / 应收表 / 银行流水</td><td>财务 / 商务</td><td>CFO</td><td>待确认</td></tr><tr><td>回款风险</td><td>逾期天数</td><td>超过约定到账日仍未到账的天数</td><td>数字</td><td>当前日期 - 约定到账日期</td><td>应收表 / 合同台账</td><td>财务 / 商务</td><td>CFO</td><td>待确认</td></tr><tr><td>回款风险</td><td>回款风险等级</td><td>当前应收款的风险级别</td><td>枚举</td><td>按逾期天数、金额、客户等级、历史到账表现综合判断</td><td>计算字段</td><td>系统</td><td>CFO</td><td>待确认</td></tr><tr><td>支出审批</td><td>是否超预算</td><td>当前支出是否超过预算额度</td><td>布尔</td><td>申请金额 + 已发生金额 &gt; 对应预算额度</td><td>预算表 / 支出申请</td><td>系统</td><td>CFO</td><td>待确认</td></tr><tr><td>支出审批</td><td>是否影响现金流</td><td>当前支出是否导致现金流缺口扩大</td><td>布尔</td><td>付款后可用现金低于安全阈值，或现金流缺口大于 0</td><td>计算字段</td><td>系统</td><td>CFO</td><td>待确认</td></tr><tr><td>支出审批</td><td>单据完整性</td><td>合同、结算单、发票等依据是否齐全</td><td>枚举</td><td>按支出类型要求校验必需单据</td><td>审批系统 / 人工上传</td><td>财务 / 行政</td><td>CFO</td><td>待确认</td></tr><tr><td>今日清单</td><td>今日必须处理事项</td><td>今天需要责任人处理的经营任务</td><td>列表</td><td>风险任务 + 到期任务 + 逾期任务 + 升级任务</td><td>任务系统 / 规则引擎</td><td>系统</td><td>负责人</td><td>待确认</td></tr><tr><td>风险派发</td><td>责任人</td><td>当前风险事项的第一处理人</td><td>用户</td><td>按客户、业务线、支出科目或组织关系匹配</td><td>人员表 / 客户归属表</td><td>业务负责人</td><td>负责人</td><td>待确认</td></tr></tbody></table><h2 id="五、建议技术字段名草案" tabindex="-1">五、建议技术字段名草案 <a class="header-anchor" href="#五、建议技术字段名草案" aria-label="Permalink to &quot;五、建议技术字段名草案&quot;">​</a></h2><p>以下字段名仅作为工程沟通草案，不作为 CEO/CFO 业务确认项。最终以接口与数据模型评审结论为准。</p><table tabindex="0"><thead><tr><th>CEO展示名称</th><th>建议技术字段名</th><th>建议类型</th><th>备注</th></tr></thead><tbody><tr><td>本月可用现金</td><td><code>available_cash_month</code></td><td>decimal</td><td>金额字段需统一币种和精度</td></tr><tr><td>本月预计回款</td><td><code>expected_collection_month</code></td><td>decimal</td><td>需区分高确定性和低确定性预计回款</td></tr><tr><td>本月实际回款</td><td><code>actual_collection_month</code></td><td>decimal</td><td>应来自已复核银行流水</td></tr><tr><td>本月计划支出</td><td><code>planned_expense_month</code></td><td>decimal</td><td>需区分已审批和待审批支出</td></tr><tr><td>本月现金流缺口</td><td><code>cash_gap_month</code></td><td>decimal</td><td>建议作为计算字段，不直接手工维护</td></tr><tr><td>管理费用可用额度</td><td><code>management_expense_available</code></td><td>decimal</td><td>依赖预算周期定义</td></tr><tr><td>应收金额</td><td><code>receivable_amount</code></td><td>decimal</td><td>需区分应收总额和未回款余额</td></tr><tr><td>逾期天数</td><td><code>overdue_days</code></td><td>integer</td><td>需确认节假日是否顺延</td></tr><tr><td>回款风险等级</td><td><code>collection_risk_level</code></td><td>enum</td><td>枚举值建议：normal / watch / high / critical</td></tr><tr><td>是否超预算</td><td><code>is_over_budget</code></td><td>boolean</td><td>可由规则引擎计算</td></tr><tr><td>是否影响现金流</td><td><code>affects_cash_flow</code></td><td>boolean</td><td>可由规则引擎计算</td></tr><tr><td>单据完整性</td><td><code>document_completeness</code></td><td>enum</td><td>建议区分 complete / missing / pending_review</td></tr><tr><td>今日必须处理事项</td><td><code>today_required_tasks</code></td><td>array</td><td>接口层可能返回任务列表</td></tr><tr><td>责任人</td><td><code>task_owner</code></td><td>object/string</td><td>需确认用户体系</td></tr></tbody></table><h2 id="六、核心算法规则" tabindex="-1">六、核心算法规则 <a class="header-anchor" href="#六、核心算法规则" aria-label="Permalink to &quot;六、核心算法规则&quot;">​</a></h2><h3 id="_6-1-本月现金流缺口" tabindex="-1">6.1 本月现金流缺口 <a class="header-anchor" href="#_6-1-本月现金流缺口" aria-label="Permalink to &quot;6.1 本月现金流缺口&quot;">​</a></h3><p>展示名称：本月现金流缺口</p><p>计算公式：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>本月现金流缺口 = 本月计划支出 - 本月可用现金 - 本月预计回款</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>判断规则：</p><ul><li>如果本月现金流缺口 &lt;= 0，状态为安全；</li><li>如果本月现金流缺口 &gt; 0，状态为存在缺口；</li><li>如果缺口金额超过 CFO 设置的安全阈值，状态为高风险。</li></ul><p>待 CFO 确认：</p><ul><li>本月可用现金是否包含短期理财或备用金；</li><li>本月预计回款是否只包含高确定性回款；</li><li>本月计划支出是否包含待审批支出；</li><li>安全阈值金额或比例。</li></ul><h3 id="_6-2-回款逾期判断" tabindex="-1">6.2 回款逾期判断 <a class="header-anchor" href="#_6-2-回款逾期判断" aria-label="Permalink to &quot;6.2 回款逾期判断&quot;">​</a></h3><p>展示名称：回款是否逾期</p><p>计算公式：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>逾期天数 = 当前日期 - 约定到账日期</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>判断规则：</p><ul><li>当前日期 &lt;= 约定到账日期：未逾期；</li><li>当前日期 &gt; 约定到账日期，且未到账：逾期；</li><li>已部分到账时，需要展示未到账金额和剩余逾期风险。</li></ul><p>待 CFO 确认：</p><ul><li>约定到账日期以合同为准，还是以历史到账日为准；</li><li>节假日是否顺延；</li><li>部分到账是否仍触发预警；</li><li>不同客户是否允许不同宽限期。</li></ul><h3 id="_6-3-回款风险等级" tabindex="-1">6.3 回款风险等级 <a class="header-anchor" href="#_6-3-回款风险等级" aria-label="Permalink to &quot;6.3 回款风险等级&quot;">​</a></h3><p>展示名称：回款风险等级</p><p>建议初版规则：</p><table tabindex="0"><thead><tr><th>风险等级</th><th>判断条件</th></tr></thead><tbody><tr><td>正常</td><td>未逾期，或逾期 0 天</td></tr><tr><td>关注</td><td>逾期 1-3 天，或金额较小但未到账</td></tr><tr><td>高风险</td><td>逾期 4-7 天，或金额较大</td></tr><tr><td>严重风险</td><td>逾期超过 7 天，或关键客户大额未到账</td></tr></tbody></table><p>待 CFO 确认：</p><ul><li>金额较大的标准；</li><li>关键客户名单；</li><li>不同业务线是否有不同风险阈值；</li><li>历史到账习惯是否参与风险等级判断。</li></ul><h3 id="_6-4-支出是否超预算" tabindex="-1">6.4 支出是否超预算 <a class="header-anchor" href="#_6-4-支出是否超预算" aria-label="Permalink to &quot;6.4 支出是否超预算&quot;">​</a></h3><p>展示名称：是否超预算</p><p>计算公式：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>支出后预算占用 = 已发生金额 + 已审批待付款金额 + 当前申请金额</span></span>
<span class="line"><span>是否超预算 = 支出后预算占用 &gt; 对应预算额度</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>待 CFO 确认：</p><ul><li>预算按月、季度还是年度控制；</li><li>预算按部门、项目、科目还是业务线控制；</li><li>是否允许负责人特批；</li><li>超预算是否直接阻断，还是只预警。</li></ul><h3 id="_6-5-支出是否影响现金流" tabindex="-1">6.5 支出是否影响现金流 <a class="header-anchor" href="#_6-5-支出是否影响现金流" aria-label="Permalink to &quot;6.5 支出是否影响现金流&quot;">​</a></h3><p>展示名称：是否影响现金流</p><p>计算公式：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>付款后可用现金 = 当前可用现金 - 当前申请付款金额</span></span>
<span class="line"><span>付款后现金流缺口 = 本月计划支出 - 付款后可用现金 - 本月预计回款</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>判断规则：</p><ul><li>付款后现金流缺口 &lt;= 0：原则可批；</li><li>付款后现金流缺口 &gt; 0：需谨慎；</li><li>付款后现金低于安全阈值：高风险，建议升级 CFO 或 CEO。</li></ul><p>待 CFO 确认：</p><ul><li>现金安全阈值；</li><li>哪些支出属于刚性支出；</li><li>哪些支出可以延后；</li><li>哪些支出必须 CEO 确认。</li></ul><h2 id="七、数据来源清单" tabindex="-1">七、数据来源清单 <a class="header-anchor" href="#七、数据来源清单" aria-label="Permalink to &quot;七、数据来源清单&quot;">​</a></h2><table tabindex="0"><thead><tr><th>数据来源</th><th>数据内容</th><th>获取方式</th><th>更新频率</th><th>维护人</th><th>复核人</th><th>V1.0 接入方式</th></tr></thead><tbody><tr><td>银行流水</td><td>收入、支出、账户余额</td><td>导入 / 手工上传 / 后续接口</td><td>每日或按需</td><td>财务</td><td>CFO</td><td>优先支持 Excel/CSV 导入</td></tr><tr><td>财务 Excel</td><td>预算、费用、收入、支出分类</td><td>文件导入</td><td>每日或每周</td><td>财务</td><td>CFO</td><td>V1.0 支持标准模板导入</td></tr><tr><td>应收表</td><td>客户、合同、应收金额、约定到账日</td><td>导入 / 人工维护</td><td>每日</td><td>财务 / 商务</td><td>CFO</td><td>V1.0 支持导入和编辑</td></tr><tr><td>支出审批数据</td><td>付款申请、科目、用途、单据</td><td>导入 / 人工录入</td><td>实时或每日</td><td>财务 / 行政</td><td>CFO</td><td>V1.0 不替代审批系统，只做判断</td></tr><tr><td>业务线收入数据</td><td>业务线、收入目标、实际收入</td><td>导入 / 人工维护</td><td>每周或每月</td><td>业务负责人</td><td>CFO / CEO</td><td>V1.0 先人工维护</td></tr><tr><td>历史回款时间</td><td>客户历史到账规律</td><td>应收表 / 银行流水计算</td><td>按月更新</td><td>财务</td><td>CFO</td><td>V1.0 可先按规则计算</td></tr><tr><td>管理费用预算规则</td><td>管理费用比例、额度、阈值</td><td>参数配置</td><td>按周期调整</td><td>CFO</td><td>CEO</td><td>V1.0 参数配置维护</td></tr><tr><td>公司 SOP</td><td>预警、升级、审批规则</td><td>文档录入</td><td>按需</td><td>产品 / CFO</td><td>CEO</td><td>V1.0 用于 AI 解释和任务派发</td></tr></tbody></table><h2 id="八、复核状态定义" tabindex="-1">八、复核状态定义 <a class="header-anchor" href="#八、复核状态定义" aria-label="Permalink to &quot;八、复核状态定义&quot;">​</a></h2><table tabindex="0"><thead><tr><th>状态</th><th>含义</th></tr></thead><tbody><tr><td>待确认</td><td>字段或规则尚未由 CFO 确认</td></tr><tr><td>已确认</td><td>字段、算法、来源已由 CFO 确认</td></tr><tr><td>待复核</td><td>数据已进入系统，但仍需财务复核</td></tr><tr><td>已复核</td><td>数据已由财务或 CFO 复核，可用于经营判断</td></tr><tr><td>已冻结</td><td>当前版本内不再随意修改，变更进入下一迭代</td></tr></tbody></table><h2 id="九、ai-回答引用规则" tabindex="-1">九、AI 回答引用规则 <a class="header-anchor" href="#九、ai-回答引用规则" aria-label="Permalink to &quot;九、AI 回答引用规则&quot;">​</a></h2><p>AI 助手回答现金流、回款、支出审批问题时，必须遵守：</p><ol><li>只能基于已确认字段、已复核数据和明确规则回答；</li><li>必须说明结论依据；</li><li>涉及金额、日期、风险等级时，必须说明数据来源；</li><li>数据未复核时，必须提示“该数据仍待 CFO/财务复核”；</li><li>不能编造缺失数据；</li><li>不能自行修改财务口径；</li><li>不能直接给出付款执行指令。</li></ol><h2 id="十、ceo-cfo-确认清单" tabindex="-1">十、CEO + CFO 确认清单 <a class="header-anchor" href="#十、ceo-cfo-确认清单" aria-label="Permalink to &quot;十、CEO + CFO 确认清单&quot;">​</a></h2><p>在进入接口与数据模型评审前，必须完成以下确认：</p><ul><li>[ ] 指标展示名称确认；</li><li>[ ] CFO 财务定义确认；</li><li>[ ] 核心公式确认；</li><li>[ ] 数据来源确认；</li><li>[ ] 数据维护人确认；</li><li>[ ] 数据复核人确认；</li><li>[ ] 现金安全阈值确认；</li><li>[ ] 回款逾期阈值确认；</li><li>[ ] 回款风险等级规则确认；</li><li>[ ] 支出预算判断规则确认；</li><li>[ ] AI 回答依据规则确认；</li><li>[ ] 未复核数据展示口径确认。</li></ul><h2 id="十一、工程团队待确认项" tabindex="-1">十一、工程团队待确认项 <a class="header-anchor" href="#十一、工程团队待确认项" aria-label="Permalink to &quot;十一、工程团队待确认项&quot;">​</a></h2><p>以下事项不需要 CEO/CFO 直接确认，但需要在接口与数据模型评审中由技术团队确认：</p><ul><li>[ ] 最终英文字段名；</li><li>[ ] 数据库存储类型；</li><li>[ ] 金额精度和币种处理；</li><li>[ ] 日期和时区规则；</li><li>[ ] 枚举值编码；</li><li>[ ] 接口返回结构；</li><li>[ ] 计算字段是否落库；</li><li>[ ] 任务列表是否独立建模；</li><li>[ ] 用户、客户、业务线之间的关联关系；</li><li>[ ] 数据复核状态是否作为通用字段。</li></ul>`,73)])])}const u=d(i,[["render",r]]);export{b as __pageData,u as default};
